import pyotp
import qrcode

# Generate TOTP secret for user
def generate_totp_secret():
    totp = pyotp.TOTP(pyotp.random_base32())
    return totp.secret

# Create QR code for authenticator app
def create_qr_code(secret, username):
    uri = pyotp.totp.TOTP(secret).provisioning_uri(name=username, issuer_name='MFA System')
    img = qrcode.make(uri)
    img.save(f'{username}_qr.png')

# Validate TOTP code
def validate_totp_code(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code)

# Sample usage
username = 'john_doe'
secret = generate_totp_secret()
create_qr_code(secret, username)
input_code = input("Enter TOTP code from authenticator app: ")
if validate_totp_code(secret, input_code):
    print("TOTP code is valid.")
else:
    print("TOTP code is invalid.")